import{_ as t,c as r,m as e,a as o,t as i,a5 as n,o as s}from"./chunks/framework.DwbewbAn.js";const q=JSON.parse('{"title":"5xx","description":"","frontmatter":{"title":"5xx"},"headers":[],"relativePath":"doc/网络协议/HTTP/状态码/5xx.md","filePath":"packages/doc/src/网络协议/HTTP/状态码/5xx.md","lastUpdated":1704643216000}'),c={name:"doc/网络协议/HTTP/状态码/5xx.md"},h={id:"frontmatter-title",tabindex:"-1"},l=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=n('<h2 id="_5xx-服务端错误" tabindex="-1">5xx <a href="https://www.zhihu.com/search?q=%E6%9C%8D%E5%8A%A1%E7%AB%AF&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A396387142%7D" target="_blank" rel="noreferrer">服务端</a>错误 <a class="header-anchor" href="#_5xx-服务端错误" aria-label="Permalink to &quot;5xx [服务端](https://www.zhihu.com/search?q=服务端&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra={&quot;sourceType&quot;%3A&quot;article&quot;%2C&quot;sourceId&quot;%3A396387142})错误&quot;">​</a></h2><p>这类状态码代表了服务器在处理请求的过程中有错误或者异常状态发生，也有可能是服务器意识到以当前的软硬件资源无法完成对请求的处理。除非这是一个HEAD 请求，否则服务器应当包含一个解释当前错误状态以及这个状况是临时的还是永久的解释信息实体。浏览器应当向用户展示任何在当前响应中被包含的实体。</p><p>这些状态码适用于任何响应方法。</p><h3 id="_500-internal-server-error" tabindex="-1">500 Internal Server Error <a class="header-anchor" href="#_500-internal-server-error" aria-label="Permalink to &quot;500 Internal Server Error&quot;">​</a></h3><p>服务器遇到了一个未曾预料的状况，导致了它无法完成对请求的处理。一般来说，这个问题都会在服务器端的源代码出现错误时出现。</p><h3 id="_501-not-implemented" tabindex="-1">501 Not Implemented <a class="header-anchor" href="#_501-not-implemented" aria-label="Permalink to &quot;501 Not Implemented&quot;">​</a></h3><p>服务器不支持当前请求所需要的某个功能。当服务器无法识别请求的方法，并且无法支持其对任何资源的请求。</p><h3 id="_502-bad-gateway" tabindex="-1">502 Bad Gateway <a class="header-anchor" href="#_502-bad-gateway" aria-label="Permalink to &quot;502 Bad Gateway&quot;">​</a></h3><p>作为网关或者代理工作的服务器尝试执行请求时，从上游服务器接收到无效的响应。</p><h3 id="_503-service-unavailable" tabindex="-1">503 Service Unavailable <a class="header-anchor" href="#_503-service-unavailable" aria-label="Permalink to &quot;503 Service Unavailable&quot;">​</a></h3><p>由于临时的服务器维护或者过载，服务器当前无法处理请求。这个状况是临时的，并且将在一段时间以后恢复。如果能够预计延迟时间，那么响应中可以包含一个 Retry-After 头用以标明这个延迟时间。如果没有给出这个 Retry-After 信息，那么客户端应当以处理500响应的方式处理它。</p><blockquote><p>注意：503状态码的存在并不意味着服务器在过载的时候必须使用它。某些服务器只不过是希望拒绝客户端的连接。</p></blockquote><h3 id="_504-gateway-timeout" tabindex="-1">504 Gateway Timeout <a class="header-anchor" href="#_504-gateway-timeout" aria-label="Permalink to &quot;504 Gateway Timeout&quot;">​</a></h3><p>作为网关或者代理工作的服务器尝试执行请求时，未能及时从上游服务器（URI标识出的服务器，例如HTTP、FTP、LDAP）或者<a href="https://www.zhihu.com/search?q=%E8%BE%85%E5%8A%A9%E6%9C%8D%E5%8A%A1%E5%99%A8&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A396387142%7D" target="_blank" rel="noreferrer">辅助服务器</a>（例如DNS）收到响应。</p><blockquote><p>注意：某些<a href="https://www.zhihu.com/search?q=%E4%BB%A3%E7%90%86%E6%9C%8D%E5%8A%A1%E5%99%A8&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A396387142%7D" target="_blank" rel="noreferrer">代理服务器</a>在DNS查询超时时会返回400或者500错误</p></blockquote><h3 id="_505-http-version-not-supported" tabindex="-1">505 HTTP Version Not Supported <a class="header-anchor" href="#_505-http-version-not-supported" aria-label="Permalink to &quot;505 HTTP Version Not Supported&quot;">​</a></h3><p>服务器不支持，或者拒绝支持在请求中使用的 HTTP 版本。这暗示着服务器不能或不愿使用与客户端相同的版本。响应中应当包含一个描述了为何版本不被支持以及服务器支持哪些协议的实体。</p><h3 id="_507-insufficient-storage" tabindex="-1">507 Insufficient Storage <a class="header-anchor" href="#_507-insufficient-storage" aria-label="Permalink to &quot;507 Insufficient Storage&quot;">​</a></h3><p>服务器无法存储完成请求所必须的内容。这个状况被认为是临时的。</p><h3 id="_511-network-authentication-required" tabindex="-1">511 Network Authentication Required <a class="header-anchor" href="#_511-network-authentication-required" aria-label="Permalink to &quot;511 Network Authentication Required&quot;">​</a></h3><p>客户端需要进行身份验证才能获得网络访问权限，旨在限制用户群访问特定网络。</p>',21);function u(a,p,_,m,b,f){return s(),r("div",null,[e("h1",h,[o(i(a.$frontmatter.title)+" ",1),l]),d])}const y=t(c,[["render",u]]);export{q as __pageData,y as default};
